#!/usr/bin/env bash
set -euo pipefail

if [[ "${BRIDGEVM_HVF_ALLOW_REAL_EDK2_FIRMWARE_RUN_LOOP:-0}" != "1" ]]; then
  echo "SKIP: set BRIDGEVM_HVF_ALLOW_REAL_EDK2_FIRMWARE_RUN_LOOP=1 to run the signed HVF firmware run-loop probe against a real AArch64 edk2 pflash image"
  exit 0
fi

ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../.." && pwd)"
cd "$ROOT"

STORE="$(mktemp -d "/tmp/bridgevm-winarm-hvf-real-edk2-firmware-run-loop.XXXXXX")"
FIRMWARE="${BRIDGEVM_AARCH64_UEFI_CODE:-/opt/homebrew/Cellar/qemu/11.0.1/share/qemu/edk2-aarch64-code.fd}"
VARS_TEMPLATE="${BRIDGEVM_AARCH64_UEFI_VARS:-/opt/homebrew/Cellar/qemu/11.0.1/share/qemu/edk2-arm-vars.fd}"
VARS="$STORE/edk2-arm-vars.fd"
INSTALLER_MEDIA_VARS="$STORE/edk2-arm-vars-installer-media.fd"
TRY_VBAR_VARS="$STORE/edk2-arm-vars-try-recommended-vbar.fd"
CONTINUE_TRY_VBAR_VARS="$STORE/edk2-arm-vars-try-recommended-vbar-continue.fd"
COMBINED_TRY_VBAR_REPAIR_VARS="$STORE/edk2-arm-vars-try-recommended-vbar-low-vector-repair.fd"
DIAGNOSTIC_VARS="$STORE/edk2-arm-vars-diagnostic.fd"
GUEST_RAM_DIAGNOSTIC_VARS="$STORE/edk2-arm-vars-guest-ram-diagnostic.fd"
EXECUTABLE_DIAGNOSTIC_VARS="$STORE/edk2-arm-vars-executable-diagnostic.fd"
REPAIR_VARS="$STORE/edk2-arm-vars-low-vector-repair.fd"
CONTINUE_REPAIR_VARS="$STORE/edk2-arm-vars-low-vector-repair-continue.fd"
RESTORE_BEFORE_ERET_VARS="$STORE/edk2-arm-vars-low-vector-restore-before-eret.fd"
REMAP_REPAIR_VARS="$STORE/edk2-arm-vars-low-vector-recommended-remap.fd"
INSTALLER_ISO="${BRIDGEVM_WINDOWS_ARM_ISO:-$ROOT/ISO/Win11_25H2_English_Arm64_v2.iso}"
INSTALLER_TARGET_DISK="$STORE/win11-arm-target.raw"

# shellcheck source=/dev/null
source "$ROOT/tests/integration/windows-arm-hvf-pflash-fixtures.sh"

if [[ ! -f "$FIRMWARE" || ! -f "$VARS_TEMPLATE" ]]; then
  echo "SKIP: real AArch64 edk2 firmware files were not found at '$FIRMWARE' and '$VARS_TEMPLATE'"
  exit 0
fi

runner_output=""
if [[ -n "${BRIDGEVM_LIVE_HVF_RUNNER:-}" ]]; then
  runner_output="$(apps/macos/scripts/build-sign-hvf-runner.sh --verify-only "$BRIDGEVM_LIVE_HVF_RUNNER")" \
    || fail "provided BRIDGEVM_LIVE_HVF_RUNNER is not a signed executable with the hypervisor entitlement"
else
  runner_output="$(apps/macos/scripts/build-sign-hvf-runner.sh)" \
    || fail "could not build/sign hvf-runner with the hypervisor entitlement"
fi
runner="$(printf '%s\n' "$runner_output" | tail -n 1)"
[[ -x "$runner" ]] || fail "signed hvf-runner path is not executable: $runner_output"

probe_vars_path() {
  local expect_path=0
  local arg
  for arg in "$@"; do
    if [[ "$expect_path" == "1" ]]; then
      printf '%s' "$arg"
      return 0
    fi
    if [[ "$arg" == "--vars" ]]; then
      expect_path=1
    fi
  done
  return 1
}

remove_retry_vars_path() {
  local vars_path="$1"
  if [[ -n "$vars_path" && "$vars_path" == "$STORE/"* ]]; then
    rm -f "$vars_path"
  fi
}

run_hvf_probe_with_retry() {
  local label="$1"
  shift
  local output=""
  local status=0
  local vars_path=""
  local attempt
  vars_path="$(probe_vars_path "$@")" || vars_path=""
  for attempt in 1 2 3; do
    status=0
    output="$("$@" 2>&1)" || status=$?
    if [[ "$output" != *"HV_DENIED"* && "$output" != *"hv_vm_create failed: 0xfae94007"* ]]; then
      printf '%s' "$output"
      return "$status"
    fi
    if [[ "$attempt" == "3" ]]; then
      printf '%s' "$output"
      return 1
    fi
    remove_retry_vars_path "$vars_path"
    echo "retrying $label after transient HV_DENIED (attempt $attempt)" >&2
    sleep "$attempt"
  done
}

output="$(run_hvf_probe_with_retry "real edk2 firmware run-loop" "$runner" --windows-firmware-run-loop-probe --firmware "$FIRMWARE" --vars-template "$VARS_TEMPLATE" --vars "$VARS" --create-vars --allow-loop --max-exits 8 --guest-ram-mib 64 --watchdog-ms 2000 --map-low-pflash-alias)" \
  || fail "hvf-runner real edk2 firmware run-loop failed: $output"

