try_vbar_output="$(run_hvf_probe_with_retry "real edk2 recommended-vector-base VBAR run-loop" "$runner" --windows-firmware-run-loop-probe --firmware "$FIRMWARE" --vars-template "$VARS_TEMPLATE" --vars "$TRY_VBAR_VARS" --create-vars --allow-loop --max-exits 4 --guest-ram-mib 64 --watchdog-ms 2000 --map-low-pflash-alias --try-recommended-vector-base-vbar)" \
